```java
@Service
@Transactional  // all methods run in a transaction by default
public class ProductService {

    private final ProductRepository repo;

    ProductService(ProductRepository repo) { this.repo = repo; }

    public Product create(String name, double price, String category) {
        if (repo.existsByName(name))
            throw new IllegalStateException("Product already exists: " + name);
        return repo.save(new Product(name, price, category));
    }

    public Optional<Product> findById(String id)         { return repo.findById(id); }
    public List<Product>     findAll()                   { return repo.findAll(); }
    public List<Product>     findByCategory(String cat)  { return repo.findByCategoryIgnoreCase(cat); }
    public List<Product>     search(String q)            { return repo.findByNameContainingIgnoreCase(q); }

    public Product update(String id, String name, double price, String category) {
        Product p = repo.findById(id).orElseThrow(() ->
            new IllegalArgumentException("Product not found: " + id));
        p.setName(name); p.setPrice(price); p.setCategory(category);
        return repo.save(p);
    }

    public void delete(String id) {
        if (!repo.existsById(id)) throw new IllegalArgumentException("Product not found: " + id);
        repo.deleteById(id);
    }
}
```

